import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { getBooking } from '../../utils/api';
import { ArrowLeft, User, MapPin, TestTube, CreditCard } from 'lucide-react';

const statusColors = {
  pending: 'badge-warning', confirmed: 'badge-info', sample_collected: 'badge-info',
  processing: 'badge-info', completed: 'badge-success', cancelled: 'badge-danger'
};
const payColors = { pending: 'badge-warning', paid: 'badge-success', failed: 'badge-danger' };

export default function BookingDetailPage() {
  const { id } = useParams();
  const [booking, setBooking] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getBooking(id).then(r => { setBooking(r.data.booking); setLoading(false); });
  }, [id]);

  if (loading) return <div className="loading-container"><div className="spinner"/></div>;
  if (!booking) return <div className="empty-state"><h3>Booking not found</h3></div>;

  return (
    <div style={{ maxWidth: 800, margin: '0 auto', padding: '28px 24px' }}>
      <Link to="/my-bookings" className="btn btn-outline btn-sm" style={{ marginBottom: 20 }}>
        <ArrowLeft size={14}/> Back to Bookings
      </Link>

      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 24, flexWrap: 'wrap', gap: 12 }}>
        <div>
          <h1 style={{ fontSize: 24, fontWeight: 700, color: 'var(--primary)' }}>Booking #{booking.booking_number}</h1>
          <p style={{ color: 'var(--text-muted)', fontSize: 13 }}>{new Date(booking.created_at).toLocaleString('en-IN')}</p>
        </div>
        <div style={{ display: 'flex', gap: 10 }}>
          <span className={`badge ${statusColors[booking.booking_status] || 'badge-muted'}`}>{booking.booking_status?.replace('_', ' ')}</span>
          <span className={`badge ${payColors[booking.payment_status] || 'badge-muted'}`}>{booking.payment_status}</span>
        </div>
      </div>

      <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
        <div className="card">
          <div style={{ display: 'flex', alignItems: 'center', gap: 8, fontWeight: 700, color: 'var(--primary)', marginBottom: 16 }}><User size={16}/> Patient Info</div>
          <div className="grid-2">
            {[['Name', booking.patient_name],['Phone', booking.patient_phone],['Age', booking.patient_age ? `${booking.patient_age} years` : '-'],['Gender', booking.patient_gender || '-'],].map(([l,v]) => (
              <div key={l}><div style={{ fontSize: 12, color: 'var(--text-muted)' }}>{l}</div><div style={{ fontWeight: 600 }}>{v}</div></div>
            ))}
          </div>
        </div>

        <div className="card">
          <div style={{ display: 'flex', alignItems: 'center', gap: 8, fontWeight: 700, color: 'var(--primary)', marginBottom: 16 }}><MapPin size={16}/> Collection Details</div>
          <div className="grid-2">
            {[['Type', booking.collection_type], ['Date', booking.collection_date || '-'], ['Time', booking.collection_time || '-']].map(([l,v]) => (
              <div key={l}><div style={{ fontSize: 12, color: 'var(--text-muted)' }}>{l}</div><div style={{ fontWeight: 600, textTransform: 'capitalize' }}>{v}</div></div>
            ))}
          </div>
        </div>

        <div className="card">
          <div style={{ display: 'flex', alignItems: 'center', gap: 8, fontWeight: 700, color: 'var(--primary)', marginBottom: 16 }}><TestTube size={16}/> Tests Ordered</div>
          <div className="table-container">
            <table>
              <thead><tr><th>Test Name</th><th>Code</th><th style={{ textAlign: 'right' }}>Price</th></tr></thead>
              <tbody>
                {booking.items?.map(item => (
                  <tr key={item.id}>
                    <td style={{ fontWeight: 600 }}>{item.test_name}</td>
                    <td><code style={{ fontSize: 11, background: 'var(--surface2)', padding: '2px 6px', borderRadius: 4 }}>{item.test_code}</code></td>
                    <td style={{ textAlign: 'right', fontWeight: 700 }}>₹{parseFloat(item.total_price).toFixed(0)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        <div className="card">
          <div style={{ display: 'flex', alignItems: 'center', gap: 8, fontWeight: 700, color: 'var(--primary)', marginBottom: 16 }}><CreditCard size={16}/> Payment</div>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <div><div style={{ fontSize: 12, color: 'var(--text-muted)' }}>Total Amount Paid</div></div>
            <div style={{ fontSize: 28, fontWeight: 700, color: 'var(--primary)', fontFamily: 'Space Mono, monospace' }}>₹{parseFloat(booking.final_amount).toFixed(0)}</div>
          </div>
          {booking.payment_id && <div style={{ fontSize: 12, color: 'var(--text-muted)', marginTop: 8 }}>Payment ID: {booking.payment_id}</div>}
        </div>
      </div>
    </div>
  );
}
